INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('mcp-server', 'reference', 'MCP Server', 'The MCP server is the only write path into Canopy. Coding agents connect over the Model Context Protocol and post the output of a work session through a typed contract; nothing else can mutate the store.

The endpoint lives at /mcp on the same origin as everything else and is bearer-only. Each request carries a personal access token in the Authorization header (Bearer canopy_mcp_…). On a missing or invalid credential the server returns a bare 401 with no WWW-Authenticate header and no OAuth discovery — clients must use the configured token. The token is compared by SHA-256 hash against the store and never logged.

A fresh MCP server instance is constructed per request (the SDK guards against reuse), and the handler is stateless — there is no Durable Object or long-lived agent. The write tools (append_feed, propose_doc_update, propose_milestone) do not write directly: they funnel through the same gate as the HTTP /ingest path, so an agent can never bypass review.', 1, '2026-06-24T10:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('mcp-server', 1, 'The MCP server is the only write path into Canopy. Coding agents connect over the Model Context Protocol and post the output of a work session through a typed contract; nothing else can mutate the store.

The endpoint lives at /mcp on the same origin as everything else and is bearer-only. Each request carries a personal access token in the Authorization header (Bearer canopy_mcp_…). On a missing or invalid credential the server returns a bare 401 with no WWW-Authenticate header and no OAuth discovery — clients must use the configured token. The token is compared by SHA-256 hash against the store and never logged.

A fresh MCP server instance is constructed per request (the SDK guards against reuse), and the handler is stateless — there is no Durable Object or long-lived agent. The write tools (append_feed, propose_doc_update, propose_milestone) do not write directly: they funnel through the same gate as the HTTP /ingest path, so an agent can never bypass review.', 'Initial published version', 'promoted', 'high', '2026-06-24T10:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('mcp-server', 2, 'The MCP server is the only write path into Canopy. Coding agents connect over the Model Context Protocol and post the output of a work session through a typed contract; nothing else can mutate the store.

The endpoint lives at /mcp and is bearer-only: a personal token in the Authorization header (Bearer canopy_mcp_…), compared by SHA-256 hash, never logged. Bad credentials get a bare 401 — no WWW-Authenticate, no OAuth discovery.

Rotation: tokens never expire on their own. Revoke and mint a new one from Settings; the old value stops working immediately. A fresh, stateless server is built per request, and the write tools funnel through the same gate as /ingest — an agent can never bypass human review.', 'Document token rotation + the per-request server lifecycle', 'staged', 'high', '2026-06-25T20:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('the-gate', 'reference', 'The Gate — the single write surface', 'Every write — from MCP and from the HTTP /ingest path alike — funnels through one set of per-entry gate functions. There is exactly one place that decides write-vs-stage-vs-triage, and adding a new write means adding it here rather than introducing a second surface.

The gate makes three guarantees. First, nothing is guessed: an out-of-vocabulary tag or section, a low-confidence flag, or a milestone marked done is routed to the needs-triage queue instead of being written blindly. Second, the author is always the authenticated principal passed in by the caller; the client-supplied author field is advisory and ignored. Third, agent writes are non-destructive — they land as staged proposals, never as live content.

This is the load-bearing invariant of the whole system: because there is a single gated path, the human review guarantee holds no matter which client is talking to Canopy.', 1, '2026-06-23T09:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('the-gate', 1, 'Every write — from MCP and from the HTTP /ingest path alike — funnels through one set of per-entry gate functions. There is exactly one place that decides write-vs-stage-vs-triage, and adding a new write means adding it here rather than introducing a second surface.

The gate makes three guarantees. First, nothing is guessed: an out-of-vocabulary tag or section, a low-confidence flag, or a milestone marked done is routed to the needs-triage queue instead of being written blindly. Second, the author is always the authenticated principal passed in by the caller; the client-supplied author field is advisory and ignored. Third, agent writes are non-destructive — they land as staged proposals, never as live content.

This is the load-bearing invariant of the whole system: because there is a single gated path, the human review guarantee holds no matter which client is talking to Canopy.', 'Initial published version', 'promoted', 'high', '2026-06-23T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('auth', 'reference', 'Auth', 'Sign-in is delegated to GitHub via OAuth with PKCE, and access is gated to active members of the SaplingLearn organization. After the OAuth exchange Canopy checks org membership; non-members are redirected to a locked dead-end (/?denied=1) and no session is created.

Humans authenticate with a signed session cookie. Agents authenticate to /mcp with a personal bearer token (canopy_mcp_… prefix), stored only as a SHA-256 hash. The principal — just a GitHub login — is resolved from the session for HTTP and from the bearer for /mcp, and is threaded into the gate as the authoritative author.

The org''s OAuth token is retained at the callback, AES-GCM-sealed under the cookie secret (no separate secret), so the roadmap can read GitHub at view time. One subtlety worth knowing: GitHub only accepts https callback URLs for public hosts, so Canopy forces the redirect_uri scheme to https except on localhost — a request that reaches the Worker over http still produces an https callback that GitHub accepts.', 1, '2026-06-25T18:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('auth', 1, 'Sign-in is delegated to GitHub via OAuth with PKCE, and access is gated to active members of the SaplingLearn organization. After the OAuth exchange Canopy checks org membership; non-members are redirected to a locked dead-end (/?denied=1) and no session is created.

Humans authenticate with a signed session cookie. Agents authenticate to /mcp with a personal bearer token (canopy_mcp_… prefix), stored only as a SHA-256 hash. The principal — just a GitHub login — is resolved from the session for HTTP and from the bearer for /mcp, and is threaded into the gate as the authoritative author.

The org''s OAuth token is retained at the callback, AES-GCM-sealed under the cookie secret (no separate secret), so the roadmap can read GitHub at view time. One subtlety worth knowing: GitHub only accepts https callback URLs for public hosts, so Canopy forces the redirect_uri scheme to https except on localhost — a request that reaches the Worker over http still produces an https callback that GitHub accepts.', 'Initial published version', 'promoted', 'high', '2026-06-25T18:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('data-model', 'reference', 'Data Model', 'Canopy is a single Cloudflare D1 (SQLite) database. The first-class objects are docs, feed entries, decisions (ADRs), and milestones; everything else supports them.

A doc has exactly one promoted version live at a time (docs.current_version), with its full history in doc_versions — each version carries a status of staged or promoted, a change summary, a confidence flag, and an author. Promotion copies a staged version''s body into the live doc and bumps current_version; prior versions are never destroyed. The feed table is an append-only log; tags live in entry_tags keyed by entry type and id. ADRs live in their own table with a draft/ratified status. needs_triage holds unplaceable items awaiting a human.

Identity tables (users, sessions, mcp_tokens) and the roadmap tables (milestones, milestone_proposals) round out the schema. The controlled vocabulary — the sections and tags the gate accepts — lives in its own tables and is the gate''s source of truth.', 1, '2026-06-20T12:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('data-model', 1, 'Canopy is a single Cloudflare D1 (SQLite) database. The first-class objects are docs, feed entries, decisions (ADRs), and milestones; everything else supports them.

A doc has exactly one promoted version live at a time (docs.current_version), with its full history in doc_versions — each version carries a status of staged or promoted, a change summary, a confidence flag, and an author. Promotion copies a staged version''s body into the live doc and bumps current_version; prior versions are never destroyed. The feed table is an append-only log; tags live in entry_tags keyed by entry type and id. ADRs live in their own table with a draft/ratified status. needs_triage holds unplaceable items awaiting a human.

Identity tables (users, sessions, mcp_tokens) and the roadmap tables (milestones, milestone_proposals) round out the schema. The controlled vocabulary — the sections and tags the gate accepts — lives in its own tables and is the gate''s source of truth.', 'Initial published version', 'promoted', 'high', '2026-06-20T12:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('feed', 'reference', 'Feed', 'The Feed is the append-only log of everything the team and its agents have done. Entries are immutable: they are never edited or deleted, and a correction is a new entry that references the original. This makes the log auditable and matches how agents actually produce output — one entry per session, never revised after the fact.

Each entry has an author (a GitHub login), a one-line summary, an optional body, and artifacts — pull requests, commits, and issue numbers — stored as JSON and rendered as links. The feed can be filtered by author and by tag at read time. Tags are drawn from the controlled vocabulary, so the filter set is always meaningful.', 1, '2026-06-22T08:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('feed', 1, 'The Feed is the append-only log of everything the team and its agents have done. Entries are immutable: they are never edited or deleted, and a correction is a new entry that references the original. This makes the log auditable and matches how agents actually produce output — one entry per session, never revised after the fact.

Each entry has an author (a GitHub login), a one-line summary, an optional body, and artifacts — pull requests, commits, and issue numbers — stored as JSON and rendered as links. The feed can be filtered by author and by tag at read time. Tags are drawn from the controlled vocabulary, so the filter set is always meaningful.', 'Initial published version', 'promoted', 'high', '2026-06-22T08:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('docs-and-versioning', 'reference', 'Docs & Versioning', 'Docs is the reading surface for promoted sections, grouped into Reference, Context, and Decisions. There is no editor on this site — pages are written by agents through the MCP contract and become live only after a human promotes them in Triage.

Versioning is non-destructive. An agent''s propose_doc_update stages a new version; the live doc is untouched until a human runs promote, which copies the staged body into the doc and advances current_version. Every prior version remains readable through the version-history control, and a page that has a newer staged proposal shows a banner linking to Triage. Exactly one version is promoted (live) at any moment.', 1, '2026-06-21T11:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('docs-and-versioning', 1, 'Docs is the reading surface for promoted sections, grouped into Reference, Context, and Decisions. There is no editor on this site — pages are written by agents through the MCP contract and become live only after a human promotes them in Triage.

Versioning is non-destructive. An agent''s propose_doc_update stages a new version; the live doc is untouched until a human runs promote, which copies the staged body into the doc and advances current_version. Every prior version remains readable through the version-history control, and a page that has a newer staged proposal shows a banner linking to Triage. Exactly one version is promoted (live) at any moment.', 'Initial published version', 'promoted', 'high', '2026-06-21T11:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('triage', 'reference', 'Triage — the human-confirm console', 'Triage is where staged agent output becomes accepted truth. It is the human half of "agents stage, humans confirm," and it is deliberately not reachable over MCP — the confirm actions are session-cookie-authenticated HTTP routes, never agent-callable tools.

There are three queues. Proposals are staged doc versions newer than the live page; promoting one makes it the live version. Decisions are drafted ADRs; ratifying one flips it from draft to ratified. Triage proper holds needs-triage items — agent output the gate could not place — for a human to assign or discard. A staged proposal shows a real line-diff against the promoted version, so the reviewer can see exactly what changes before clicking Promote.', 1, '2026-06-19T15:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('triage', 1, 'Triage is where staged agent output becomes accepted truth. It is the human half of "agents stage, humans confirm," and it is deliberately not reachable over MCP — the confirm actions are session-cookie-authenticated HTTP routes, never agent-callable tools.

There are three queues. Proposals are staged doc versions newer than the live page; promoting one makes it the live version. Decisions are drafted ADRs; ratifying one flips it from draft to ratified. Triage proper holds needs-triage items — agent output the gate could not place — for a human to assign or discard. A staged proposal shows a real line-diff against the promoted version, so the reviewer can see exactly what changes before clicking Promote.', 'Initial published version', 'promoted', 'high', '2026-06-19T15:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('roadmap', 'reference', 'Roadmap', 'The Roadmap is a timeline of coarse milestones — the altitude above individual GitHub issues. Each milestone has a title, a target date, and a status of upcoming, in progress, or done.

Progress is computed live from GitHub at view time and stored nowhere. A milestone''s github_ref is a bare reference — a GitHub milestone number, or a JSON array of issue numbers — resolved against the configured repository using the viewer''s stored OAuth token. If the token is absent, expired, or lacks access (for example a private repo read with only read:org scope), the milestone is returned without progress rather than as an error, and the bar renders as unavailable. Completion is never inferred from 100% issue closure: marking a milestone done is always a deliberate human confirm.', 1, '2026-06-18T10:00:00Z', 'AndresL230');
