INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by) VALUES ('search', 'reference', 'Search', 'Search spans docs, feed entries, and decisions in one ranked list. The current implementation is a straightforward text match in D1; the result shape — a type, a title, and a snippet — is fixed so that semantic ranking can be added later without changing the surface the reader sees.

A section filter narrows to docs only; without it, feed and ADR matches are included. The query is highlighted inside each snippet on the client.', 1, '2026-06-17T14:00:00Z', 'AndresL230');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('search', 1, 'Search spans docs, feed entries, and decisions in one ranked list. The current implementation is a straightforward text match in D1; the result shape — a type, a title, and a snippet — is fixed so that semantic ranking can be added later without changing the surface the reader sees.

